// Only forward messages that are replies on a thread with more than one message
// (i.e. skip the original outbound email n8n itself sent).
return items.filter(i => i.json.threadMessageCount > 1).map(i => ({ json: {
  gmailThreadId: i.json.threadId,
  fromEmail: i.json.from,
  bodySnippet: (i.json.snippet || '').slice(0, 1000),
  receivedAt: new Date(Number(i.json.internalDate)).toISOString()
}}));

const crypto = require('crypto');
const secret = $env.N8N_WEBHOOK_SECRET;
return items.map(item => {
  const body = JSON.stringify(item.json);
  const signature = crypto.createHmac('sha256', secret).update(body).digest('hex');
  return { json: { ...item.json, __signature: signature } };
});
